/**
 * Properties for the Backtop component.
 */
export interface BacktopProps extends _BacktopProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Theme color of the component.
   */
  color?: ThemeColor;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Visual variant of the component.
   */
  variant?: ButtonVariant;
  /**
   * Shape of the component.
   */
  shape?: ButtonShape;
  /**
   * Shadow style of the component.
   */
  shadow?: ButtonShadow;
  /**
   * Whether the component should fit its content width.
   */
  fitContent?: boolean;
  /**
   * The icon name of iconify.
   *
   * @default 'lucide:arrow-up'
   */
  icon?: string;
  /**
   * The class of the icon.
   */
  iconClass?: ClassValue;
  /**
   * The props of the icon.
   */
  iconProps?: Partial<IconProps>;
}

/**
 * Events for the Backtop component.
 */
export type BacktopEmits = _BacktopEmits;

// @unocss-include
import { cv } from '@soybeanjs/cva';
import { buttonVariants } from './button';

export const backtopVariants = cv({
  extend: [buttonVariants],
  base: 'fixed z-50',
  variants: {
    size: {
      xs: 'bottom-4 end-4',
      sm: 'bottom-5 end-5',
      md: 'bottom-6 end-6',
      lg: 'bottom-7 end-7',
      xl: 'bottom-8 end-8',
      '2xl': 'bottom-10 end-10'
    }
  },
  defaultVariants: {
    size: 'md'
  }
});

